-- Name: proc_expanded_hts(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_expanded_hts()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE partition_name TEXT;
DECLARE period_date DATE;
DECLARE period_text TEXT;
DECLARE period_start DATE;
DECLARE period_end DATE;

BEGIN

SELECT TIMEOFDAY() INTO start_time;

SELECT start_date INTO period_start
FROM expanded_hts_prep.period WHERE is_active;

SELECT date INTO period_end
FROM expanded_hts_prep.period WHERE is_active;

SELECT table_name_hts INTO partition_name
from expanded_hts_prep.period where is_active;

SELECT periodid INTO period_text
from expanded_hts_prep.period where is_active;

SELECT date INTO period_date 
FROM expanded_hts_prep.period where is_active;

EXECUTE format('DROP TABLE IF EXISTS expanded_hts_prep.%I',partition_name);

EXECUTE format('CREATE TABLE expanded_hts_prep.%I PARTITION OF expanded_hts_prep.expanded_hts_weekly
			   FOR VALUES FROM (%L) TO (%L)', partition_name, period_start,period_end);
			   
			   
EXECUTE format('ALTER TABLE expanded_hts_prep.%I
			   ADD CONSTRAINT %I_check CHECK (period_start_date >= %L 
			   and period_end_date <= %L)', partition_name,partition_name,period_start,period_end);
			   
EXECUTE format('INSERT INTO expanded_hts_prep.%I
select %L as period,
clientcode,
datim_id,
firstname,
surname,
othername,
sex,
age,
dateofbirth,
phonenumber,
maritalstatus,
lgaofresidence,
stateofresidence,
facility,
state,
lga,
patientid,
education,
occupation,
datimcode,
htslatitude,
htslongitude,
clientaddress,
datevisit,
firsttimevisit,
numberofchildren,
numberofwives,
indexclient,
prepoffered,
prepaccepted,
previouslytested,
targetgroup,
referredfrom,
testingsetting,
counselingtype,
pregnancystatus,
breastfeeding,
indextype,
ifrecencytestingoptin,
recencyid,
recencytesttype,
recencytestdate,
viralloadreceivedresultdate,
recencyinterpretation,
finalrecencyresult,
viralloadresult,
viralloadsamplecollectiondate,
viralloadconfirmationresult,
viralloadconfirmationdate,
assessmentcode,
modality,
syphilistestresult,
hepatitisbtestresult,
hepatitisctestresult,
cd4type,
cd4testresult,
finalhivtestresult,
dateofhivtesting,
numberofcondomsgiven,
numberoflubricantsgiven,
%L as period_start_date,
%L as period_end_date,
entrypoint
FROM expanded_hts_prep.expanded_hts_joined', partition_name, period_text, period_start, period_end);

-- DROP TABLE IF EXISTS expanded_hts_prep.expanded_hts_joined;

update expanded_hts_prep.expanded_hts_weekly
set firstname = '******' where firstname != '******';

update expanded_hts_prep.expanded_hts_weekly
set othername = '******' where othername != '******';

update expanded_hts_prep.expanded_hts_weekly
set surname = '******' where surname != '******';

INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time) 
VALUES ('expanded_hts', start_time);
END
$$;


ALTER PROCEDURE expanded_hts_prep.proc_expanded_hts() OWNER TO lamisplus_etl;

