SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_hts_prep.cte_prep_baseline_urinalysis_new;
CREATE TABLE expanded_hts_prep.cte_prep_baseline_urinalysis_new AS
SELECT 
pc.urinalysis ->> 'result' as result, 
--pc.urinalysis->>'testDate' as test_date, 
CAST ((CASE WHEN pc.urinalysis->>'testDate' = '' THEN NULL ELSE pc.urinalysis->>'testDate' END) AS DATE) as test_date,
min.person_uuid, min.ods_datim_id 
FROM ods_prep_clinic pc JOIN (SELECT DISTINCT MIN(date(urinalysis->> 'testDate')) test_date, person_uuid, ods_datim_id 
FROM ods_prep_clinic where urinalysis is not null
GROUP BY person_uuid, ods_datim_id)min ON min.person_uuid=pc.person_uuid AND min.ods_datim_id=pc.ods_datim_id
WHERE pc.urinalysis IS NOT NULL AND test_date IS NOT NULL;

