-- Name: proc_prep_bio(); Type: PROCEDURE; Schema: expanded_hts_prep; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_hts_prep.proc_prep_bio()
    LANGUAGE plpgsql
    AS $_$
DECLARE start_time TIMESTAMP;

BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_hts_prep.cte_prep_bio_new;
CREATE TABLE expanded_hts_prep.cte_prep_bio_new AS
SELECT * FROM (SELECT p.id, p.uuid, p.ods_datim_id, REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(CAST(address_object->>'line' AS text), '"', ''), ']', ''), '[', ''), 'null',''), '\\\\\\\', '') AS address,
    CASE WHEN address_object->>'stateId'  ~ '^\\\\d(\\\\.\\\\d)?$' THEN address_object->>'stateId' ELSE null END  AS stateId,
    CASE WHEN address_object->>'district'  ~ '^\\\\d(\\\\.\\\\d)?$' THEN address_object->>'district' ELSE null END  AS lgaId
    FROM ods_patient_person p
    left join jsonb_array_elements(p.address-> 'address') as l(address_object) on true) r;

drop table if exists expanded_hts_prep.cte_prep_bio;

alter table expanded_hts_prep.cte_prep_bio_new rename to cte_prep_bio;

INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time) 
VALUES ('cte_prep_bio', start_time);

END
$_$;


ALTER PROCEDURE expanded_hts_prep.proc_prep_bio() OWNER TO lamisplus_etl;

