alter table expanded_hts_prep.cte_prep_current_wbc
alter column other_test_date TYPE date USING other_test_date::date;

INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time) 
VALUES ('cte_prep_current_wbc', start_time);

END
$$;


