--

CREATE PROCEDURE expanded_hts_prep.proc_prep_prepc()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;

BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_hts_prep.cte_prep_prepc_new;
CREATE TABLE expanded_hts_prep.cte_prep_prepc_new AS
SELECT pc.person_uuid, pc.ods_datim_id, MAX(pc.encounter_date) as encounter_date, pc.duration,
(CASE WHEN (pc.encounter_date  + pc.duration) > (SELECT date from expanded_hts_prep.period where is_active) THEN 'Active'
ELSE  'Defaulted' END) status FROM ods_prep_clinic pc
INNER JOIN (SELECT DISTINCT MAX(pc.encounter_date) encounter_date, pc.person_uuid
FROM ods_prep_clinic pc GROUP BY pc.person_uuid) max_p ON max_p.encounter_date=pc.encounter_date
AND max_p.person_uuid=pc.person_uuid
WHERE pc.archived=0
GROUP BY pc.ods_datim_id, pc.person_uuid, pc.duration, status;

drop table if exists expanded_hts_prep.cte_prep_prepc;

alter table expanded_hts_prep.cte_prep_prepc_new rename to cte_prep_prepc;

INSERT INTO expanded_hts_prep.expanded_hts_prep_monitoring (table_name, start_time) 
VALUES ('cte_prep_prepc', start_time);

END
$$;


