--
-- Name: get_partition_creation_times(); Type: FUNCTION; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE FUNCTION expanded_radet.get_partition_creation_times() RETURNS TABLE(partition_name text, creation_time timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
DECLARE
    partition_record RECORD;
    db_oid OID;
BEGIN
    -- Get the OID of the current database
    SELECT oid INTO db_oid FROM pg_database WHERE datname = current_database();

    FOR partition_record IN
        SELECT relname, relfilenode
        FROM pg_class
        WHERE relname LIKE 'expanded_radet_weekly_%' AND relkind = 'r'
    LOOP
        RETURN QUERY EXECUTE format(
            'SELECT %L AS partition_name, (pg_stat_file(''base/%s/%s'')).modification AS creation_time',
            partition_record.relname,
            db_oid,
            partition_record.relfilenode
        );
    END LOOP;
END;
$$;


ALTER FUNCTION expanded_radet.get_partition_creation_times() OWNER TO lamisplus_etl;

--
-- Name: proc_bio_data(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_bio_data()
    LANGUAGE plpgsql
    AS $_$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

drop table if exists expanded_radet.cte_bio_data_new;

create table expanded_radet.cte_bio_data_new AS
SELECT DISTINCT ON (p.uuid, p.ods_datim_id) 
    p.uuid AS personUuid, 
    p.ods_datim_id AS bio_ods_datim_id,
    '******' AS hospitalNumber, 
    h.unique_id AS uniqueId, 
    EXTRACT(
      YEAR 
      FROM 
        AGE((select date from expanded_radet.period where is_active), CAST(p.date_of_birth AS DATE))
    ) AS age, 
    INITCAP(p.sex) AS gender, 
    p.date_of_birth AS dateOfBirth, 
    facility.facility_name AS facilityName, 
    facility.facility_lga AS lga, 
    facility.facility_state AS state, 
    facility.datim_id AS datimId, 
    tgroup.display AS targetGroup, 
    eSetting.display AS enrollmentSetting, 
    hac.visit_date AS artStartDate, 
    hr.description AS regimenAtStart, 
    p.date_of_registration AS dateOfRegistration, 
    h.date_of_registration AS dateOfEnrollment, 
    h.ovc_number AS ovcUniqueId, 
    h.house_hold_number AS householdUniqueNo, 
    ecareEntry.display AS careEntry, 
    hrt.description AS regimenLineAtStart 
FROM 
    ods_patient_person p 
    LEFT OUTER JOIN central_partner_mapping facility ON facility.facility_id = p.facility_id  AND facility.datim_id = p.ods_datim_id
    INNER JOIN ods_hiv_enrollment h ON h.person_uuid = p.uuid  AND h.ods_datim_id = p.ods_datim_id
    LEFT OUTER JOIN ods_base_application_codeset tgroup ON tgroup.id = h.target_group_id AND tgroup.ods_datim_id = h.ods_datim_id
    LEFT OUTER JOIN ods_base_application_codeset eSetting ON eSetting.id = h.enrollment_setting_id AND eSetting.ods_datim_id = h.ods_datim_id
    LEFT OUTER JOIN ods_base_application_codeset ecareEntry ON ecareEntry.id = h.entry_point_id AND ecareEntry.ods_datim_id = h.ods_datim_id
    INNER JOIN ods_hiv_art_clinical hac ON hac.hiv_enrollment_uuid = h.uuid  AND hac.ods_datim_id = h.ods_datim_id
    AND hac.archived = 0 
    INNER JOIN ods_hiv_regimen hr ON hr.id = hac.regimen_id  AND hr.ods_datim_id = hac.ods_datim_id
    LEFT OUTER JOIN ods_hiv_regimen_type hrt ON hrt.id = hac.regimen_type_id  AND hrt.ods_datim_id = hac.ods_datim_id
WHERE 
    h.archived = 0 AND p.archived = 0 
    AND hac.is_commencement = TRUE 
    AND hac.visit_date >= '1980-01-01' ---$2
    AND hac.visit_date <= (select date from expanded_radet.period where is_active)  ---$3
	;


drop table expanded_radet.cte_bio_data;
alter table expanded_radet.cte_bio_data_new rename to cte_bio_data;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_bio_data', start_time,end_time);

END
$_$;


ALTER PROCEDURE expanded_radet.proc_bio_data() OWNER TO lamisplus_etl;

--
-- Name: proc_biometric(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_biometric()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_biometric_new;

CREATE TABLE expanded_radet.cte_biometric_new AS
SELECT 
		  DISTINCT ON (he.person_uuid, he.ods_datim_id) he.person_uuid AS person_uuid60,
		  he.ods_datim_id as biome_ods_datim_id,
		  biometric_count.enrollment_date AS dateBiometricsEnrolled, 
		  biometric_count.count AS numberOfFingersCaptured,
		  cast(recapture_count.recapture_date as date) AS dateBiometricsRecaptured,
		  recapture_count.count AS numberOfFingersRecaptured,
		  bst.biometric_status AS biometricStatus, 
		  bst.status_date
		FROM 
		  ods_hiv_enrollment he 
		  LEFT JOIN (
			SELECT 
			  DISTINCT on (b.person_uuid, b.ods_datim_id) b.person_uuid, b.ods_datim_id,
			  CASE WHEN COUNT(b.person_uuid) > 10 THEN 10 ELSE COUNT(b.person_uuid) END, 
			  MAX(enrollment_date) enrollment_date 
			FROM 
			  ods_biometric b 
			WHERE 
			  archived = 0 
			  AND (recapture = 0 or recapture is null) 
			GROUP BY 
			  b.person_uuid, b.ods_datim_id
		  ) biometric_count ON biometric_count.person_uuid = he.person_uuid AND
		  biometric_count.ods_datim_id = he.ods_datim_id
		  LEFT JOIN (
			SELECT 
			  DISTINCT ON(r.person_uuid, r.ods_datim_id)r.person_uuid, r.ods_datim_id,
			  CASE WHEN COUNT(r.person_uuid) > 10 THEN 10 ELSE COUNT(r.person_uuid) END, 
			  MAX(enrollment_date) recapture_date 
			FROM 
			  ods_biometric r 
			WHERE 
			  archived = 0 
			  AND recapture = 1 
			GROUP BY 
			  r.person_uuid, r.ods_datim_id
		  ) recapture_count ON recapture_count.person_uuid = he.person_uuid 
		  LEFT JOIN (
		SELECT DISTINCT ON (person_id, ods_datim_id) person_id, ods_datim_id, biometric_status,
		MAX(status_date) OVER (PARTITION BY person_id, ods_datim_id ORDER BY status_date DESC) AS status_date 
		FROM ods_hiv_status_tracker 
            WHERE archived=0 
				  --AND facility_id=?1
              ) bst ON bst.person_id = he.person_uuid AND bst.ods_datim_id = he.ods_datim_id 
            WHERE 
              he.archived = 0;

drop table expanded_radet.cte_biometric;
alter table expanded_radet.cte_biometric_new rename to cte_biometric;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('biometric', start_time,end_time);

END
$$;


ALTER PROCEDURE expanded_radet.proc_biometric() OWNER TO lamisplus_etl;

