CREATE PROCEDURE expanded_radet.proc_cryptocol_antigen()
    LANGUAGE plpgsql
    AS $$DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_radet.subcte_cryptococal_antigen;
CREATE TABLE expanded_radet.subcte_cryptococal_antigen AS
select lr.patient_uuid as personuuid12,lr.ods_datim_id as crypt_ods_datim_id,
