lr.result_reported AS lastCrytococalAntigen , 
ROW_NUMBER() OVER (PARTITION BY lr.patient_uuid, lr.ods_datim_id ORDER BY lr.date_result_reported DESC) as rowNumcrypt 
from public.ods_laboratory_test lt 
inner join ods_laboratory_result lr on lr.test_id = lt.id 
AND lr.ods_datim_id = lt.ods_datim_id
where lab_test_id = 52 OR lab_test_id = 69 OR lab_test_id = 70 AND lr.date_result_reported IS NOT NULL 
AND lr.date_result_reported <= (select date from expanded_radet.period where is_active) ---?3 
AND lr.date_result_reported >= '1980-01-01' ---?2 
AND lr.result_reported is NOT NULL AND lr.archived = '0';

CREATE INDEX IF NOT EXISTS rowNumcrypt_subcte_cryptococalantigen
ON expanded_radet.subcte_cryptococal_antigen(rowNumcrypt);

DROP TABLE if exists expanded_radet.cte_cryptococal_antigen_new;
CREATE TABLE expanded_radet.cte_cryptococal_antigen_new AS
select *  from expanded_radet.subcte_cryptococal_antigen
where rowNumcrypt = 1;

