CREATE INDEX IF NOT EXISTS personuuiddatim_cryptococalantigen
ON expanded_radet.cte_cryptococal_antigen(personuuid12,crypt_ods_datim_id);

DROP TABLE IF EXISTS expanded_radet.subcte_cryptococal_antigen;

SELECT TIMEOFDAY() INTO end_time;
