CREATE PROCEDURE hts_prep_datamart.proc_final_htsquery_datamart()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE partition_name TEXT;
DECLARE period_date DATE;
DECLARE period_text TEXT;
DECLARE period_start DATE;
DECLARE period_end DATE;

BEGIN

SELECT TIMEOFDAY() INTO start_time;

SELECT start_date INTO period_start
FROM expanded_hts_prep.period WHERE is_active;

SELECT date INTO period_end
FROM expanded_hts_prep.period WHERE is_active;

SELECT table_name_hts INTO partition_name
from expanded_hts_prep.period where is_active;

SELECT periodid INTO period_text
from expanded_hts_prep.period where is_active;

SELECT date INTO period_date 
FROM expanded_hts_prep.period where is_active;

EXECUTE format('DROP TABLE IF EXISTS hts_prep_datamart.%I',partition_name);

EXECUTE format('CREATE TABLE hts_prep_datamart.%I PARTITION OF hts_prep_datamart.final_htsquery_datamart
			   FOR VALUES FROM (%L) TO (%L)', partition_name, period_start,period_end);
			   
			   
--EXECUTE format('ALTER TABLE hts_prep_datamart.%I
--			   ADD CONSTRAINT %I_check CHECK (period_start_date >= %L 
--			   and period_end_date <= %L)', partition_name,partition_name,period_start,period_end);
			   
EXECUTE format('INSERT INTO hts_prep_datamart.%I
select %L as period,
clientcode,
datim_id,
firstname,
surname,
othername,
sex,
age,
dateofbirth,
phonenumber,
maritalstatus,
lgaofresidence,
stateofresidence,
facility,
state,
lga,
patientid,
education,
occupation,
datimcode,
htslatitude,
htslongitude,
clientaddress,
datevisit,
firsttimevisit,
numberofchildren,
numberofwives,
indexclient,
prepoffered,
prepaccepted,
previouslytested,
targetgroup,
referredfrom,
testingsetting,
counselingtype,
pregnancystatus,
breastfeeding,
indextype,
ifrecencytestingoptin,
recencyid,
recencytesttype,
recencytestdate,
viralloadreceivedresultdate,
recencyinterpretation,
finalrecencyresult,
viralloadresult,
viralloadsamplecollectiondate,
viralloadconfirmationresult,
viralloadconfirmationdate,
assessmentcode,
modality,
syphilistestresult,
hepatitisbtestresult,
hepatitisctestresult,
cd4type,
cd4testresult,
finalhivtestresult,
dateofhivtesting,
numberofcondomsgiven,
numberoflubricantsgiven,
entrypoint,
%L as period_start_date,
%L as period_end_date
FROM expanded_hts_prep.expanded_hts_joined', partition_name, period_text, period_start, period_end);

--DROP TABLE IF EXISTS hts_prep.hts_joined;

update hts_prep_datamart.final_htsquery_datamart
set firstname = '******' where firstname != '******';

update hts_prep_datamart.final_htsquery_datamart
set othername = '******' where othername != '******';

update hts_prep_datamart.final_htsquery_datamart
set surname = '******' where surname != '******';

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO hts_prep_datamart.hts_prep_monitoring (table_name, start_time,end_time) 
VALUES ('final_htsquery_datamart', start_time,end_time);
END
$$;


ALTER PROCEDURE hts_prep_datamart.proc_final_htsquery_datamart() OWNER TO lamisplus_etl;

--
-- Name: proc_final_prepquery_datamart(); Type: PROCEDURE; Schema: hts_prep_datamart; Owner: lamisplus_etl
--

CREATE PROCEDURE hts_prep_datamart.proc_final_prepquery_datamart()
    LANGUAGE plpgsql
    AS $_$DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
DECLARE partition_name TEXT;
DECLARE period_date DATE;
DECLARE period_text TEXT;
DECLARE period_start DATE;
DECLARE period_end DATE;

BEGIN
SELECT TIMEOFDAY() INTO start_time;

SELECT start_date INTO period_start
FROM expanded_hts_prep.period WHERE is_active;

SELECT date INTO period_end
FROM expanded_hts_prep.period WHERE is_active;

SELECT table_name_prep INTO partition_name
from expanded_hts_prep.period where is_active;

SELECT periodid INTO period_text
from expanded_hts_prep.period where is_active;

SELECT date INTO period_date 
FROM expanded_hts_prep.period where is_active;

EXECUTE format('DROP TABLE IF EXISTS hts_prep_datamart.%I',partition_name);

EXECUTE format('CREATE TABLE hts_prep_datamart.%I PARTITION OF hts_prep_datamart.final_prepquery_datamart
			   FOR VALUES FROM (%L) TO (%L)',
			   partition_name, period_start,period_end);
			   
			   
--EXECUTE format('ALTER TABLE hts_prep_datamart.%I
--			   ADD CONSTRAINT %I_check CHECK (period_start_date >= %L 
--			   and period_end_date <= %L)',
--			   partition_name,partition_name,period_start,period_end);
			   
INSERT INTO hts_prep_datamart.final_prepquery_datamart
select period_text,*,period_start,period_end 
from (SELECT DISTINCT ON (p.uuid, p.ods_datim_id)p.uuid AS PersonUuid,
p.id, p.uuid,p.hospital_number as hospitalNumber,
'' AS surname, '' as firstName,
he.date_of_registration AS hivEnrollmentDate,
EXTRACT(YEAR from AGE(NOW(),  date_of_birth)) as age,
'' as otherName, p.sex as sex, p.date_of_birth as dateOfBirth,
p.date_of_registration as dateOfRegistration, p.marital_status->>'display' as maritalStatus,
education->>'display' as education, p.employment_status->>'display' as occupation,
facility.name as facilityName, facility_lga.name as lga, facility_state.name as state,
p.ods_datim_id as datimId, 
CASE WHEN p.address->'address'->0->'stateId'->>0 IS NOT NULL AND p.address->'address'->0->'stateId'->>0 ~ '^[0-9]+$'
THEN (SELECT name FROM ods_base_organisation_unit WHERE id = CAST(NULLIF(p.address->'address'->0 ->'stateId' ->> 0,'') AS BIGINT) and ods_datim_id=p.ods_datim_id)
        ELSE NULL END as residentialState,
CASE WHEN p.address->'address'->0->'district'->>0 IS NOT NULL AND p.address->'address'->0->'district'->>0 ~ '^[0-9]+$'
THEN (SELECT name FROM ods_base_organisation_unit WHERE id = CAST(NULLIF(p.address->'address'->0 ->'district' ->> 0,'') AS BIGINT) and ods_datim_id=p.ods_datim_id)
ELSE NULL END as residentialLga,
(CASE WHEN contact_point->'contactPoint'->0->>'type'='phone' THEN contact_point->'contactPoint'->0->>'value' ELSE null END) AS phone,
r.address as address,
baseline_reg.regimen AS baselineRegimen,
(select display from ods_base_application_codeset where code = baseline_reg.prep_type and ods_datim_id=p.ods_datim_id) as prepType,
(select display from ods_base_application_codeset where code = baseline_pc.prep_distribution_setting and ods_datim_id=p.ods_datim_id) AS prepDistributionSetting,
baseline_bp.systolic AS baselineSystolicBP,
baseline_bp.diastolic AS baselineDiastolicBP,
baseline_pc.weight AS baselineWeight,
baseline_pc.height AS baselineHeight,
(CASE WHEN tg.display IS NOT NULL THEN tg.display 
WHEN etg.display IS NOT NULL THEN etg.display
ELSE NULL END) AS targetGroup,
baseline_pc.encounter_date AS prepCommencementDate,
baseline_urinalysis.result AS baseLineUrinalysis,
cast(baseline_urinalysis.test_date AS date) as baseLineUrinalysisDate,
baseline_creatinine.other_test_result AS baseLineCreatinine,
cast(baseline_creatinine.other_test_date as date) AS baseLineCreatinineTestDate,
baseline_alt.other_test_result AS baseLineAlt,
baseline_hbsag.other_test_result AS baseLineHbsag,
baseline_hbpcv.other_test_result AS baseLineHbPcv,
baseline_wbc.other_test_result AS baseLineWbc,
current_alt.other_test_result as currentAlt,
cast(current_alt.other_test_date as date) as currentAltDate,
current_hbsag.other_test_result as currentHbsag,
cast(current_hbsag.other_test_date as date) as currentHbsagDate,
current_hbpcv.other_test_result as currentHbpcv,
cast(current_hbpcv.other_test_date as date) as currentHbpcvDate,
current_wbc.other_test_result as currentWbc,
cast(current_wbc.other_test_date as date) as currentWbcDate,
(CASE WHEN baseline_pc.hepatitis->>'result' LIKE 'Hepatitis B%'
THEN baseline_pc.hepatitis->>'result' ELSE NULL END) AS baseLineHepatitisB,
(CASE WHEN baseline_pc.hepatitis->>'result' LIKE 'Hepatitis C%'
THEN baseline_pc.hepatitis->>'result' ELSE NULL END) AS baseLineHepatitisC,
(select display from ods_base_application_codeset where code = current_pi.interruption_type and ods_datim_id=p.ods_datim_id) as InterruptionType,
current_pi.reason_stopped AS InterruptionReason,
current_pi.interruption_date AS InterruptionDate,
(CASE WHEN baseline_hiv_status.display IS NULL AND base_eli_test.base_eli_hiv_result IS NOT NULL
THEN base_eli_test.base_eli_hiv_result ELSE
REPLACE(baseline_hiv_status.display, 'HIV ', '') END) AS HIVStatusAtPrEPInitiation,
(CASE WHEN prepe.extra->'prep'->>'onDemandIndication' IS NOT NULL THEN prepe.extra->>'onDemandIndication'
WHEN riskt.display IS NOT NULL THEN riskt.display ELSE NULL END) AS indicationForPrEP,
current_reg.regimen AS currentRegimen, 
current_pc.duration AS currentDuration,
(SELECT display FROM ods_base_application_codeset where code = current_reg.prep_type and ods_datim_id=p.ods_datim_id) as currentPrepType,
(select display from ods_base_application_codeset where code = current_pc.prep_distribution_setting and ods_datim_id=p.ods_datim_id) AS currentPrepDistributionSetting,
current_pc.encounter_date AS DateOfLastPickup,
current_pc.systolic AS currentSystolicBP,
current_pc.diastolic AS currentDiastolicBP,
current_pc.weight AS currentWeight,
current_pc.height AS currentHeight,
current_pc.urinalysis->>'result' AS currentUrinalysis,
(SELECT display from ods_base_application_codeset where code = current_pc.family_planning and ods_datim_id=p.ods_datim_id) AS familyPlanning,
current_pc.date_of_family_planning AS dateOfFamilyPlanning,
CAST(current_pc.urinalysis->>'testDate' AS DATE) AS currentUrinalysisDate,
(CASE WHEN current_hiv_status.display IS NULL AND eli_hiv_result IS NOT NULL THEN eli_hiv_result
WHEN current_hiv_status.display IS NOT NULL THEN REPLACE(current_hiv_status.display, 'HIV ', '')
WHEN he.date_started IS NOT NULL THEN 'Positive' ELSE NULL
END) AS currentHivStatus,
current_pc.encounter_date AS DateOfCurrentHIVStatus,
(CASE WHEN p.sex='Male' THEN NULL
WHEN current_pc.pregnant IS NOT NULL AND current_pc.pregnant='true' 
THEN (SELECT display FROM ods_base_application_codeset WHERE code = current_pc.pregnant and ods_datim_id=p.ods_datim_id)
ELSE 'Not Pregnant' END) AS pregnancyStatus,
(CASE
WHEN prepi.interruption_date  > prepc.encounter_date THEN bac.display
WHEN prepc.status IS NOT NULL THEN prepc.status
ELSE NULL END) AS CurrentStatus,
(CASE
WHEN prepi.interruption_date  > prepc.encounter_date THEN prepi.interruption_date
WHEN prepc.status IS NOT NULL THEN prepc.encounter_date
ELSE NULL END) AS DateOfCurrentStatus
FROM public.ods_patient_person p
INNER JOIN expanded_hts_prep.cte_prep_bio r ON r.uuid=p.uuid AND r.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_pc current_pc ON current_pc.person_uuid=p.uuid AND current_pc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_pc baseline_pc ON baseline_pc.person_uuid=p.uuid AND baseline_pc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_bp baseline_bp ON baseline_bp.person_uuid=p.uuid AND baseline_bp.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_urinalysis baseline_urinalysis ON baseline_urinalysis.person_uuid=p.uuid AND baseline_urinalysis.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_creatinine baseline_creatinine ON baseline_creatinine.person_uuid=p.uuid AND baseline_creatinine.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_alt baseline_alt ON baseline_alt.person_uuid=p.uuid AND baseline_alt.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_hbsag baseline_hbsag ON baseline_hbsag.person_uuid=p.uuid AND baseline_hbsag.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_hbpcv baseline_hbpcv ON baseline_hbpcv.person_uuid=p.uuid AND baseline_hbpcv.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_baseline_wbc baseline_wbc ON baseline_wbc.person_uuid=p.uuid AND baseline_wbc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_alt current_alt ON current_alt.person_uuid=p.uuid AND current_alt.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_hbsag current_hbsag ON current_hbsag.person_uuid=p.uuid AND current_hbsag.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_hbpcv current_hbpcv ON current_hbpcv.person_uuid=p.uuid AND current_hbpcv.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_current_wbc current_wbc ON current_wbc.person_uuid=p.uuid AND current_wbc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_prepi prepi ON prepi.person_uuid=p.uuid AND  prepi.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_prepc prepc ON prepc.person_uuid=p.uuid AND prepc.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_eli_test eli_test ON eli_test.person_uuid=p.uuid AND eli_test.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_base_eli_test base_eli_test ON base_eli_test.person_uuid=p.uuid AND base_eli_test.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_e_target e_target ON e_target.person_uuid=p.uuid AND e_target.ods_datim_id=p.ods_datim_id
LEFT JOIN expanded_hts_prep.cte_prep_penrol penrol ON penrol.person_uuid=p.uuid AND penrol.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_organisation_unit facility ON facility.id=p.facility_id AND facility.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_organisation_unit facility_lga ON facility_lga.id=facility.parent_organisation_unit_id AND facility_lga.ods_datim_id=facility.ods_datim_id
LEFT JOIN ods_base_organisation_unit facility_state ON facility_state.id=facility_lga.parent_organisation_unit_id AND facility_state.ods_datim_id=facility_lga.ods_datim_id
LEFT JOIN ods_base_organisation_unit res_state ON res_state.id=CAST(r.stateid AS BIGINT) and res_state.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_organisation_unit res_lga ON res_lga.id=CAST(r.lgaid AS BIGINT) AND res_lga.ods_datim_id=p.ods_datim_id
INNER JOIN ods_prep_enrollment prepe ON prepe.person_uuid = p.uuid AND prepe.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_application_codeset riskt ON riskt.code = prepe.risk_type AND riskt.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_application_codeset tg ON tg.code = penrol.target_group AND tg.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_application_codeset etg ON etg.code = e_target.eli_target AND etg.ods_datim_id=p.ods_datim_id
LEFT JOIN (SELECT DISTINCT pi.* FROM ods_prep_interruption pi)current_pi ON current_pi.person_uuid=p.uuid AND current_pi.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_prep_regimen current_reg ON current_reg.id = current_pc.regimen_id
LEFT JOIN ods_base_application_codeset current_hiv_status ON current_hiv_status.code = current_pc.hiv_test_result
AND current_hiv_status.ods_datim_id = current_pc.ods_datim_id
LEFT JOIN ods_prep_regimen baseline_reg ON baseline_reg.id = baseline_pc.regimen_id
LEFT JOIN ods_base_application_codeset baseline_hiv_status ON baseline_hiv_status.code=baseline_pc.hiv_test_result 
AND baseline_hiv_status.ods_datim_id=baseline_pc.ods_datim_id
LEFT JOIN ods_hiv_enrollment he ON he.person_uuid = p.uuid AND he.ods_datim_id = p.ods_datim_id
LEFT JOIN ods_base_application_codeset bac ON bac.code=prepi.interruption_type
WHERE p.archived=0 
AND p.date_of_registration BETWEEN '1980-01-01' 
AND (select date from expanded_hts_prep.period where is_active))u;

update hts_prep_datamart.final_prepquery_datamart
set firstname = '******' where firstname != '******';

update hts_prep_datamart.final_prepquery_datamart
set othername = '******' where othername != '******';

update hts_prep_datamart.final_prepquery_datamart
set surname = '******' where surname != '******';

update hts_prep_datamart.final_prepquery_datamart
set phone = '******' where phone != '******';

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO hts_prep_datamart.hts_prep_monitoring (table_name, start_time,end_time) 
VALUES ('final_prepquery_datamart', start_time,end_time);
END
$_$;


ALTER PROCEDURE hts_prep_datamart.proc_final_prepquery_datamart() OWNER TO lamisplus_etl;

