--
-- Name: proc_pharmacy(); Type: PROCEDURE; Schema: maternal_cohort; Owner: lamisplus_etl
--

CREATE PROCEDURE maternal_cohort.proc_pharmacy()
    LANGUAGE plpgsql
    AS $$

DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN
	SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists maternal_cohort.pharmacy_new;

CREATE TABLE maternal_cohort.pharmacy_new AS 
SELECT hp.ods_datim_id,
	(CASE WHEN hp.visit_date + hp.refill_period + INTERVAL '29 day' < current_date THEN 'IIT' ELSE 'Active' END) status,
	(CASE WHEN hp.visit_date + hp.refill_period + INTERVAL '29 day' < current_date THEN hp.visit_date + hp.refill_period + INTERVAL '29 day'
	ELSE hp.visit_date END) AS visit_date,hp.person_uuid,MAXDATE 
FROM maternal_cohort.target_pharmacies hp
INNER JOIN maternal_cohort.MAX ON MAX.MAXDATE = hp.visit_date AND MAX.person_uuid = hp.person_uuid AND max.ods_datim_id=hp.ods_datim_id
WHERE hp.archived = 0 AND MAX.rnkkk3 = 1 AND hp.visit_date < (SELECT date from pmtct_hts.period WHERE is_active);

drop table if exists maternal_cohort.pharmacy;
alter table maternal_cohort.pharmacy_new rename to pharmacy;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO maternal_cohort.cte_monitoring (table_name, start_time,end_time) VALUES ('max', start_time,end_time);

END
$$;


ALTER PROCEDURE maternal_cohort.proc_pharmacy() OWNER TO lamisplus_etl;

