--
-- Name: proc_pmtct_maternal_cohort(); Type: PROCEDURE; Schema: maternal_cohort; Owner: lamisplus_etl
--

CREATE PROCEDURE maternal_cohort.proc_pmtct_maternal_cohort()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE partition_name TEXT;
DECLARE period_date DATE;
DECLARE period_text TEXT;
DECLARE period_start DATE;
DECLARE period_end DATE;

BEGIN

SELECT TIMEOFDAY() INTO start_time;

SELECT start_date INTO period_start
FROM pmtct_hts.period WHERE is_active;

SELECT date INTO period_end
FROM pmtct_hts.period WHERE is_active;

SELECT table_name_maternal_cohort INTO partition_name
from pmtct_hts.period where is_active;

SELECT periodid INTO period_text
from pmtct_hts.period where is_active;

SELECT date INTO period_date 
FROM pmtct_hts.period where is_active;

EXECUTE format('DROP TABLE IF EXISTS maternal_cohort.%I',partition_name);

EXECUTE format('CREATE TABLE maternal_cohort.%I PARTITION OF maternal_cohort.pmtct_maternal_cohort
FOR VALUES FROM (%L) TO (%L)', partition_name, period_start,period_end);


--EXECUTE format('ALTER TABLE maternal_cohort.%I
--			   ADD CONSTRAINT %I_check CHECK (period_start_date >= %L 
--			   and period_end_date <= %L)', partition_name,partition_name,period_start,period_end);

EXECUTE format('INSERT INTO maternal_cohort.%I
select %L as period,
"Patient ID",
    "State",
    "LGA",
    "Datim ID",
    "Facility",
    "Mother Hospital Number",
    "Mother Unique ID",
    "Mother Date of Birth",
    "Age" numeric,
    "Marital Status",
    "ANC Setting",
    "Modality",
    "Point of Entry",
    "Date of Index ANC Registration",
    "LMP Date",
    "Gestational Age (Weeks) @ First ANC visit",
    "Gravida" integer,
    "Parity" integer,
    "PCV @ANC registration",
    "Hepatitis B Test Result",
    "Treated for Hepatitis B",
    "Syphilis Test Result",
    "TB screening Status",
    "Date tested for HIV",
    "Type of HIV test",
    "Mother ART Start Date",
    "Timing of ART initiation in mother",
    "Current Pregnancy Status",
    "GA at last viisit (weeks)" smallint,
    "Mother Current ART Status",
    "Visit Status",
    "Mother DSD Status",
    "Due Date for VL Sample collection @ 32 weeks",
    "Date for VL sample collection @ 32 weeks",
    "VL result at 32-36 weeks GA",
    "Current Viral load Result",
    "Date of Current VL" date,
    "Expected Date of Delivery",
    "Place of Delivery",
    "Mode of Delivery",
    "Fetal outcome (Child status)",
    "Child hospital ID number",
    "Sex - Child",
    "Birth Weight",
    "Date of ARV Prophylaxis Commencemment",
    "Type of Prophylaxis (ePNP or regular)",
    "Date of CTX (Cotrimoxazole)",
    "Current infant fedding options",
    "Date of First DNA PCR Sample collection",
    "Result of first DNA PCR test",
    "Date of Second DNA PCR test sample collection",
    "Result of second DNA PCR test",
    "Date second DNA PCR result was received" date,
    "Date of confirmatory DNA PCR test sample collection",
    "Result of confirmatory DNA PCR test",
    "Date confirmatory DNA PCT result was received",
    "Sample collection date for Confirmatory DBS (if DBS positive)",
    "Result of Confirmatory DBS",
    "Date of Child Final Outcome test",
    "Result (Child Final Outcome)",
    "Child ART Start Date",
    "Child Unique ID",
%L as period_start_date,
%L as period_end_date
FROM maternal_cohort.pmtct_maternal_cohort_joined', partition_name, period_text, period_start, period_end);

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO maternal_cohort.cte_monitoring (table_name, start_time,end_time) VALUES ('pmtct_maternal_cohort', start_time,end_time);

END$$;


ALTER PROCEDURE maternal_cohort.proc_pmtct_maternal_cohort() OWNER TO lamisplus_etl;

--
-- Name: proc_pmtct_maternal_cohort_joined(); Type: PROCEDURE; Schema: maternal_cohort; Owner: lamisplus_etl
--

CREATE PROCEDURE maternal_cohort.proc_pmtct_maternal_cohort_joined()
    LANGUAGE plpgsql
    AS $$

DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists maternal_cohort.pmtct_maternal_cohort_joined_new;

CREATE TABLE maternal_cohort.pmtct_maternal_cohort_joined_new AS 
select DISTINCT ON (p.uuid)p.uuid AS "Patient ID",
facility_state.name as "State", 
facility_lga.name as "LGA", 
p.ods_datim_id as "Datim ID", 
facility.name as "Facility",
p.hospital_number as "Mother Hospital Number", 
he.unique_id as "Mother Unique ID",p.date_of_birth as "Mother Date of Birth", 
EXTRACT(YEAR from AGE(NOW(),  date_of_birth))"Age",p.marital_status->>'display' as "Marital Status", 
(case when anc_setting_anc is null then null when anc_setting_anc ilike '%acility%' then 'Facility' else 'Community' end) as "ANC Setting", 
anc.anc_setting_anc as "Modality",pmtctenroll.entry_point as "Point of Entry",anc.first_anc_date as "Date of Index ANC Registration", 
(case when anc.anc_no is not null then anc.lmp else pmtctenroll.lmp end) AS "LMP Date", anc.gaweeks_anc as "Gestational Age (Weeks) @ First ANC visit", 
(case when anc.anc_no is not null then anc.gravida_anc else pmtctenroll.gravida end) as "Gravida", anc.parity_anc  as "Parity", 
'' as "PCV @ANC registration", pmtctenroll.hepatitisb as "Hepatitis B Test Result",anc.treated_syphilis  as "Treated for Hepatitis B", 
anc.test_result_syphilis_anc as "Syphilis Test Result", ho.tb_screening_status as "TB screening Status",
'' as "Date tested for HIV",'' as "Type of HIV test",pmtctenroll.art_start_date as "Mother ART Start Date",pmtctenroll.art_start_time as "Timing of ART initiation in mother",
hc.pregnancystatus as "Current Pregnancy Status",pmv.ga_of_viral_load as "GA at last viisit (weeks)",
ast.currentstatus as "Mother Current ART Status",pmv.visit_status as "Visit Status",pmv.dsd_option as "Mother DSD Status",
anc.lmp + interval '32 weeks' as "Due Date for VL Sample collection @ 32 weeks",
(select min(date_of_viral_load) from public.ods_pmtct_mother_visitation where person_uuid = uuid and ga_of_viral_load > 32) as "Date for VL sample collection @ 32 weeks",
(select result_of_viral_load from public.ods_pmtct_mother_visitation where person_uuid = uuid and ga_of_viral_load > 32 order by date_of_viral_load asc limit 1) as "VL result at 32-36 weeks GA", 
cvl.currentviralload as "Current Viral load Result",cvl.dateofcurrentviralload as "Date of Current VL",delivery.date_of_delivery as "Expected Date of Delivery",
delivery.place_of_delivery as "Place of Delivery",delivery.mode_of_delivery as "Mode of Delivery",
delivery.child_status as "Fetal outcome (Child status)",pii.hospital_number as "Child hospital ID number",
pii.sex as "Sex - Child",pii.body_weight as "Birth Weight",
pia.infant_arv_time as "Date of ARV Prophylaxis Commencemment",pia.infant_arv_type as "Type of Prophylaxis (ePNP or regular)",
pia.age_at_ctx as "Date of CTX (Cotrimoxazole)",delivery.feeding_decision as "Current infant fedding options",
first.date_result_received_at_facility as "Date of First DNA PCR Sample collection",
first.results as "Result of first DNA PCR test",second.date_sample_collected as "Date of Second DNA PCR test sample collection",
second.results as "Result of second DNA PCR test",second.date_result_received_at_facility as "Date second DNA PCR result was received",
confirm.date_sample_collected as "Date of confirmatory DNA PCR test sample collection",confirm.results as "Result of confirmatory DNA PCR test",
confirm.date_result_received_at_facility as "Date confirmatory DNA PCT result was received",'' as "Sample collection date for Confirmatory DBS (if DBS positive)",
'' as "Result of Confirmatory DBS",'' as "Date of Child Final Outcome test",'' as "Result (Child Final Outcome)",
'' as "Child ART Start Date",pii.hospital_number as "Child Unique ID"
FROM ods_patient_person p
left join public.ods_hiv_enrollment he on he.person_uuid = p.uuid and he.ods_datim_id=p.ods_datim_id
left JOIN maternal_cohort.hiv_observation ho on ho.person_uuid = p.uuid and ho.ods_datim_id=p.ods_datim_id
left JOIN public.final_radet hc on hc.uniquepersonuuid = p.uuid and hc.datim_id=p.ods_datim_id
--INNER JOIN maternal_cohort.result r ON r.id=p.id and r.ods_datim_id=p.ods_datim_id
LEFT JOIN pmtct_hts.result r ON r.uuid=p.uuid and r.ods_datim_id=p.ods_datim_id
LEFT JOIN maternal_cohort.pmtct_anc anc ON p.uuid = anc.person_uuid_anc and p.ods_datim_id=anc.ods_datim_id
LEFT JOIN maternal_cohort.pmtct_delivery delivery ON p.uuid = delivery.person_uuid and p.ods_datim_id=delivery.ods_datim_id
LEFT JOIN public.ods_base_organisation_unit facility ON facility.id=p.facility_id and facility.ods_datim_id=p.ods_datim_id
LEFT JOIN public.ods_base_organisation_unit facility_lga ON facility_lga.id=facility.parent_organisation_unit_id and facility_lga.ods_datim_id=facility.ods_datim_id
LEFT JOIN public.ods_base_organisation_unit facility_state ON facility_state.id=facility_lga.parent_organisation_unit_id and facility_state.ods_datim_id=facility_lga.ods_datim_id
--LEFT JOIN public.ods_base_organisation_unit res_state ON res_state.id=CAST(r.stateid AS BIGINT) and res_state.ods_datim_id=r.ods_datim_id
LEFT JOIN ods_base_organisation_unit res_state ON res_state.id=CAST(-1 AS BIGINT) and res_state.ods_datim_id=r.ods_datim_id
LEFT JOIN ods_base_organisation_unit res_lga ON res_lga.id=CAST(-1 AS BIGINT) and res_lga.ods_datim_id=r.ods_datim_id
--LEFT JOIN public.ods_base_organisation_unit res_lga ON res_lga.id=CAST(r.lgaid AS BIGINT) and res_lga.ods_datim_id=r.ods_datim_id
LEFT JOIN public.ods_base_organisation_unit_identifier boui ON boui.organisation_unit_id=p.facility_id AND boui.name='DATIM_ID' and boui.ods_datim_id=p.ods_datim_id
left JOIN public.ods_pmtct_enrollment pmtctenroll ON pmtctenroll.person_uuid = p.uuid and pmtctenroll.ods_datim_id=p.ods_datim_id
left join maternal_cohort.pmtct_mother_visitation pmv on pmv.person_uuid = p.uuid and pmv.ods_datim_id=p.ods_datim_id
left join public.final_radet ast on p.uuid = ast.uniquepersonuuid and p.ods_datim_id=ast.datim_id
left join public.ods_pmtct_infant_information pii on pii.mother_person_uuid = p.uuid and pii.ods_datim_id=p.ods_datim_id
left join public.ods_pmtct_infant_arv pia on pia.uuid = p.uuid and pia.ods_datim_id=p.ods_datim_id
left join maternal_cohort.first first on first.uuid = p.uuid and first.ods_datim_id=p.ods_datim_id
left join maternal_cohort.second second on second.uuid = p.uuid and second.ods_datim_id=p.ods_datim_id
left join maternal_cohort.confirm confirm on confirm.uuid = p.uuid and confirm.ods_datim_id=p.ods_datim_id
left join expanded_radet.cte_current_vl_result cvl on cvl.person_uuid130 = p.uuid and cvl.cvl_ods_datim_id=p.ods_datim_id
WHERE p.archived=0 and p.sex='Female' and anc.anc_no is not null or pmtctenroll.entry_point ilike '%PMTCT_ENTRY%'
and p.date_of_registration BETWEEN CAST('1980-01-01' AS DATE) AND (SELECT date FROM pmtct_hts.period WHERE is_active)
--(SELECT date FROM expanded_radet.period WHERE is_active)
;

drop table if exists maternal_cohort.pmtct_maternal_cohort_joined;
alter table maternal_cohort.pmtct_maternal_cohort_joined_new rename to pmtct_maternal_cohort_joined;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO maternal_cohort.cte_monitoring (table_name, start_time,end_time) VALUES ('pmtct_maternal_cohort_joined', start_time,end_time);

END
$$;


