-- Name: proc_result(); Type: PROCEDURE; Schema: maternal_cohort; Owner: lamisplus_etl
--

CREATE PROCEDURE maternal_cohort.proc_result()
    LANGUAGE plpgsql
    AS $_$

DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN
	SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists maternal_cohort.result_new;

CREATE TABLE maternal_cohort.result_new AS 
SELECT p.id,p.ods_datim_id, CONCAT(CAST(address_object->>'city' AS VARCHAR), ' ', 
REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(CAST(address_object->>'line' AS text), '\\\\\\\\', ''), ']', ''), '[', ''), 'null',''),
 '\\\\\\\', '')) AS address,
CASE WHEN address_object->>'stateId'  ~ '^\\\\d+(\\\\.\\\\d+)?$' THEN address_object->>'stateId' ELSE null END  AS stateId,
CASE WHEN address_object->>'district'  ~ '^\\\\d+(\\\\.\\\\d+)?$' THEN address_object->>'district' ELSE null END  AS lgaId
FROM ods_patient_person p,
jsonb_array_elements(p.address-> 'address') with ordinality l(address_object);

drop table if exists maternal_cohort.result;
alter table maternal_cohort.result_new rename to result;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO maternal_cohort.cte_monitoring (table_name, start_time,end_time) VALUES ('result', start_time,end_time);

END
$_$;


