-- Name: proc_biometric_report_with_desired_columns(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_biometric_report_with_desired_columns()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists public.biometric_report_with_desired_columns_new;

CREATE TABLE public.biometric_report_with_desired_columns_new AS 
SELECT pp.uuid, fbc.hashed,fbc.last_modified_by,fbc.count_unique_person_uuid,b.template_type,b.device_name,b.biometric_type,
pp.full_name,(pp.contact_point->'contactPoint'->0->'value')::text AS phone_number,
	hac.last_clinic_visit_date,hap.last_pharmacy_visit_date,cpm.ip_name,cpm.facility_name,
    le.latest_enrollment_date,le.latest_created_date,le.last_modified_date,vs.*,hs.hiv_status
FROM public.first_biometric_combined fbc
LEFT JOIN public.latest_enrollment le ON le.person_uuid = fbc.uuids_with_same_hashed
LEFT JOIN public.ods_patient_person pp ON pp.uuid=fbc.uuids_with_same_hashed
LEFT JOIN public.triage_vital_sign vs ON vs.person_uuid=fbc.uuids_with_same_hashed
LEFT JOIN public.hiv_art_clinical hac ON hac.person_uuid=fbc.uuids_with_same_hashed
LEFT JOIN public.hiv_art_pharmacy hap ON hap.person_uuid=fbc.uuids_with_same_hashed
LEFT JOIN public.central_partner_mapping cpm ON fbc.facility_id=cpm.facility_id
LEFT JOIN public.hiv_status_tracker hs ON hs.person_id=fbc.uuids_with_same_hashed
left join (select distinct hashed,device_name,template_type,biometric_type
		   from public.ods_biometric where hashed is not null) b on b.hashed=fbc.hashed
order by count_unique_person_uuid desc, hashed;

drop table if exists public.biometric_report_with_desired_columns;

alter table public.biometric_report_with_desired_columns_new rename to biometric_report_with_desired_columns;

CREATE INDEX idx_biometric_report_with_desired_columns ON public.biometric_report_with_desired_columns (hashed);
CREATE INDEX idx2_biometric_report_with_desired_columns ON public.biometric_report_with_desired_columns (facility_name);
CREATE INDEX idx3_biometric_report_with_desired_columns ON public.biometric_report_with_desired_columns (ip_name);
CREATE INDEX idx4_biometric_report_with_desired_columns ON public.biometric_report_with_desired_columns (uuid);
CREATE INDEX idx5_biometric_report_with_desired_columns ON public.biometric_report_with_desired_columns (latest_enrollment_date);
CREATE INDEX idx6_biometric_report_with_desired_columns ON public.biometric_report_with_desired_columns (last_modified_date);

INSERT INTO cte_monitoring (table_name, start_time) VALUES ('biometric_report_with_desired_columns', start_time);
END$$;


ALTER PROCEDURE public.proc_biometric_report_with_desired_columns() OWNER TO lamisplus_etl;

--
-- Name: proc_current_regimen(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_current_regimen()
    LANGUAGE plpgsql
    AS $$DECLARE 
    start_time TIMESTAMP;
BEGIN
    SELECT TIMEOFDAY() INTO start_time;
    
    DROP TABLE IF EXISTS public.cte_current_regimen_new;
    
    CREATE TABLE public.cte_current_regimen_new AS
    SELECT DISTINCT ON (regiment_table.person_uuid) 
        regiment_table.person_uuid AS person_uuid70, 
        regiment_table.ods_datim_id AS creg_ods_datim_id,
        regiment_table.start_or_regimen AS dateOfCurrentRegimen, 
        regiment_table.max_visit_date,
        regiment_table.regimen
    FROM
    (
        SELECT DISTINCT ON (person_uuid, ods_datim_id) 
            person_uuid, 
            ods_datim_id,
            MIN(visit_date) AS start_or_regimen, 
            MAX(visit_date) AS max_visit_date, 
            regimen
        FROM
        (
            SELECT DISTINCT ON (hap.person_uuid, hap.ods_datim_id) 
                hap.person_uuid, 
                hap.ods_datim_id, 
                hap.id, 
                hap.visit_date, 
                hivreg.description AS regimen,
                ROW_NUMBER() OVER (ORDER BY hap.person_uuid, hap.visit_date) AS rn1,
                ROW_NUMBER() OVER (PARTITION BY hivreg.description ORDER BY hap.person_uuid, hap.visit_date) AS rn2
            FROM public.ods_hiv_art_pharmacy AS hap
            INNER JOIN (
                SELECT MAX(hapr.id) AS id, 
                       art_pharmacy_id, 
                       regimens_id, 
                       hr.description, 
                       hapr.ods_datim_id
                FROM public.ods_hiv_art_pharmacy_regimens AS hapr
                INNER JOIN public.ods_hiv_regimen AS hr ON hapr.regimens_id = hr.id
                WHERE hr.regimen_type_id IN (1,2,3,4,14)
                GROUP BY art_pharmacy_id, regimens_id, hr.description, hapr.ods_datim_id
            ) AS hapr ON hap.id = hapr.art_pharmacy_id 
                AND hap.archived = 0 
                AND hap.ods_datim_id = hapr.ods_datim_id
            INNER JOIN public.ods_hiv_regimen AS hivreg ON hapr.regimens_id = hivreg.id 
                AND hapr.ods_datim_id = hivreg.ods_datim_id
            INNER JOIN public.ods_hiv_regimen_type AS hivregtype ON hivreg.regimen_type_id = hivregtype.id 
                AND hapr.ods_datim_id = hivregtype.ods_datim_id
                AND hivreg.regimen_type_id IN (1,2,3,4,14)
            ORDER BY hap.person_uuid, hap.ods_datim_id, hap.visit_date
        ) AS t
        GROUP BY person_uuid, ods_datim_id, regimen, rn1 - rn2
        ORDER BY person_uuid, ods_datim_id
    ) AS regiment_table
    INNER JOIN (
        SELECT DISTINCT MAX(visit_date) AS max_visit_date, 
                        person_uuid, 
                        ods_datim_id
        FROM public.ods_hiv_art_pharmacy 
        WHERE archived = 0 
        GROUP BY person_uuid, ods_datim_id
    ) AS hap ON regiment_table.person_uuid = hap.person_uuid 
        AND regiment_table.ods_datim_id = hap.ods_datim_id
        AND regiment_table.max_visit_date = hap.max_visit_date
    ORDER BY regiment_table.person_uuid, regiment_table.ods_datim_id;

    DROP TABLE IF EXISTS public.cte_current_regimen;

    ALTER TABLE public.cte_current_regimen_new RENAME TO cte_current_regimen;

    INSERT INTO cte_monitoring (table_name, start_time) VALUES ('cte_current_regimen', start_time);
END;
$$;


ALTER PROCEDURE public.proc_current_regimen() OWNER TO lamisplus_etl;

--
-- Name: proc_encrypt_hts_tables(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_encrypt_hts_tables()
    LANGUAGE plpgsql
    AS $$

DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

UPDATE public.ods_hts_client
SET extra = jsonb_set(
    jsonb_set(
        jsonb_set(
            jsonb_set(
                extra, 
                '{first_name}', 
                '"******"', 
                true
            ), 
            '{middle_name}', 
            '"******"', 
            true
        ), 
        '{surname}', 
        '"******"', 
        true
    ), 
    '{phone_number}', 
    '"******"', 
    true
)
WHERE extra ->> 'first_name' != '******';

UPDATE public.ods_hts_index_elicitation
SET first_name='******', last_name='******', 
	middle_name='******', phone_number='******',
	alt_phone_number='******'
WHERE first_name != '******';

update ods_patient_person
set first_name='******', surname='******', other_name='******'
WHERE first_name!='******';

UPDATE expanded_hts_prep.expanded_prep_weekly
SET hospitalnumber='******'
WHERE hospitalnumber != '******';

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO cte_monitoring (table_name, start_time,end_time) 
VALUES ('update_hts_tables', start_time,end_time);
END
$$;


ALTER PROCEDURE public.proc_encrypt_hts_tables() OWNER TO lamisplus_etl;

