CREATE PROCEDURE public.proc_first_biometric_combined()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
BEGIN
	SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists public.first_biometric_combined_new;

CREATE TABLE public.first_biometric_combined_new AS 
SELECT hashed, last_modified_by,facility_id,
        unnest(string_to_array(STRING_AGG(person_uuid, ', '), ', ')) AS uuids_with_same_hashed,
        COUNT(DISTINCT person_uuid) AS count_unique_person_uuid 
    FROM (SELECT DISTINCT hashed, person_uuid, last_modified_by, facility_id 
        FROM public.ods_biometric WHERE recapture > 0 AND hashed IS NOT NULL) AS subquery 
    GROUP BY hashed, last_modified_by, facility_id;

drop table if exists public.first_biometric_combined;
alter table public.first_biometric_combined_new rename to first_biometric_combined;
CREATE INDEX idx_first_biometric_combined ON public.first_biometric_combined (uuids_with_same_hashed);
INSERT INTO cte_monitoring (table_name, start_time) VALUES ('first_biometric_combined', start_time);
END$$;


