--

CREATE PROCEDURE public.proc_hiv_status_tracker()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists public.hiv_status_tracker_new;

CREATE TABLE public.hiv_status_tracker_new AS 
SELECT distinct hst.person_id person_id,max_status_date,hst.hiv_status
FROM public.ods_hiv_status_tracker hst
INNER JOIN (SELECT person_id,MAX(status_date) AS max_status_date
FROM public.ods_hiv_status_tracker GROUP BY person_id) AS max_dates 
ON hst.person_id = max_dates.person_id AND hst.status_date = max_dates.max_status_date;

drop table if exists public.hiv_status_tracker;

alter table public.hiv_status_tracker_new rename to hiv_status_tracker;

CREATE INDEX idx_hiv_status_tracker ON public.hiv_status_tracker (person_id);

INSERT INTO cte_monitoring (table_name, start_time) VALUES ('hiv_status_tracker', start_time);
END$$;


