--
-- Name: proc_loop_through_lists(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_loop_through_lists()
    LANGUAGE plpgsql
    AS $$
DECLARE
    inputs text[];
    input text;
    partition_name text;
BEGIN
    -- Populate the array with values from the existing table
--     SELECT array_agg(DISTINCT ip_name)
--     INTO inputs
--     FROM public.central_partner_mapping;
	SELECT array_agg(DISTINCT periodcode)
	INTO inputs
	FROM expanded_radet.period;

    -- Loop through each input value and execute the dynamic query
    FOREACH input IN ARRAY inputs
    LOOP
        partition_name := CONCAT('aggregate_flatfile_',input);
        
		EXECUTE format('
            DROP TABLE IF EXISTS public.%I 
           ', partition_name);
			
        -- Loop through and create partitions
        EXECUTE format('
            CREATE TABLE IF NOT EXISTS public.%I 
            PARTITION OF public.aggregate_flatfile_backup
            FOR VALUES IN (%L)', partition_name, input);
    END LOOP;
END;
$$;


ALTER PROCEDURE public.proc_loop_through_lists() OWNER TO lamisplus_etl;

--
-- Name: proc_loop_through_ods_tables(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_loop_through_ods_tables()
    LANGUAGE plpgsql
    AS $$
DECLARE
    inputs text[];
    input text;
    frontend_table_name text;
	constraint_column text;
	ods_table text;
	
BEGIN
	TRUNCATE public.ods_count_monitoring;
    -- Populate the array with values from the existing table
    SELECT array_agg(ods_table_info)
    INTO inputs
    FROM public.ods_tables;

    -- Loop through each input value and execute the dynamic query
    FOREACH input IN ARRAY inputs
    LOOP
        frontend_table_name := REPLACE(split_part(input, '-', 1),'ods_','');
		ods_table := split_part(input, '-', 1);
		constraint_column := split_part(input, '-', 2);

        -- Call the function to process each lab test
        PERFORM public.generate_weekly_count_ods_tables(ods_table,frontend_table_name,
														constraint_column);

    END LOOP;
END;
$$;


ALTER PROCEDURE public.proc_loop_through_ods_tables() OWNER TO lamisplus_etl;

