--
-- Name: proc_pharmacy_query(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_pharmacy_query()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
BEGIN
	SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists public.cte_pharmacy_query_new;

CREATE TABLE public.cte_pharmacy_query_new AS 
SELECT DISTINCT ON (p.uuid, p.ods_datim_id)
    result.id,result.facility_id AS facilityId,
    p.hospital_number AS hospitalNum,hrt.description AS regimenLine,
    result.mmd_type AS mmdType,result.next_appointment AS nextAppointment,
    dd.dsd_model AS dsdModel,result.visit_date AS dateVisit,
    result.duration AS refillPeriod,result.regimen_name AS regimens
FROM (
    SELECT h.*, pharmacy_object ->> 'duration' AS duration, 
        CAST(pharmacy_object ->> 'regimenName' AS VARCHAR) AS regimen_name
    FROM ods_hiv_art_pharmacy h,
    jsonb_array_elements(h.extra->'regimens') WITH ORDINALITY p(pharmacy_object)
	WHERE ods_datim_id in (select datim_id from central_partner_mapping where ip_name='ACE-1')
	) AS result
LEFT JOIN ods_dsd_devolvement dd ON result.person_uuid = dd.person_uuid and result.ods_datim_id=dd.ods_datim_id
LEFT JOIN ods_patient_person p ON p.uuid = result.person_uuid AND p.ods_datim_id = result.ods_datim_id
LEFT JOIN ods_hiv_regimen hr ON hr.description = result.regimen_name AND hr.ods_datim_id = result.ods_datim_id
LEFT JOIN ods_hiv_regimen_type hrt ON hrt.id = hr.regimen_type_id AND hrt.ods_datim_id = hr.ods_datim_id
WHERE result.archived = 0
ORDER BY p.uuid, p.ods_datim_id, result.next_appointment, result.visit_date DESC;

drop table if exists public.cte_pharmacy_query;

alter table public.cte_pharmacy_query_new rename to cte_pharmacy_query;
CREATE INDEX idx_cte_pharmacy_query ON public.cte_pharmacy_query (person_uuid);
INSERT INTO cte_monitoring (table_name, start_time) VALUES ('cte_pharmacy_query', start_time);
END$$;


ALTER PROCEDURE public.proc_pharmacy_query() OWNER TO lamisplus_etl;

