--

CREATE PROCEDURE public.proc_risk_stratification_report()
    LANGUAGE plpgsql
    AS $$
DECLARE 
    start_time TIMESTAMP;
	end_time TIMESTAMP;
BEGIN
-- Capture start time
SELECT CURRENT_TIMESTAMP INTO start_time;

-- Drop table if it exists
DROP TABLE IF EXISTS public.risk_stratification_report;

-- Create new table with distinct records
CREATE TABLE public.risk_stratification_report AS	
SELECT DISTINCT ON (hrs.person_uuid, hrs.ods_datim_id) hrs.person_uuid, hrs.ods_datim_id, 
obac.display AS modality
FROM public.ods_hts_risk_stratification hrs
LEFT JOIN public.ods_base_application_codeset obac 
ON obac.ods_datim_id = hrs.ods_datim_id AND obac.code = hrs.modality
WHERE hrs.archived = 0 AND obac.archived = 0;

-- Capture end time
SELECT CURRENT_TIMESTAMP INTO end_time;

-- Log the operation in expanded_radet_monitoring
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time, end_time) 
VALUES ('risk_stratification_report', start_time, end_time);

END;
$$;


