--
-- Name: proc_triage_vital_sign(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_triage_vital_sign()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists public.triage_vital_sign_new;

CREATE TABLE public.triage_vital_sign_new AS 
SELECT distinct tvs.person_uuid person_uuid,max_capture_date,tvs.height,tvs.temperature,
	tvs.pulse,tvs.respiratory_rate
FROM public.ods_triage_vital_sign tvs
INNER JOIN (SELECT person_uuid,MAX(capture_date) AS max_capture_date 
FROM public.ods_triage_vital_sign GROUP BY person_uuid) AS max_dates 
ON tvs.person_uuid = max_dates.person_uuid AND tvs.capture_date = max_dates.max_capture_date;

drop table if exists public.triage_vital_sign;

alter table public.triage_vital_sign_new rename to triage_vital_sign;

CREATE INDEX idx_triage_vital_sign ON public.triage_vital_sign (person_uuid);

INSERT INTO cte_monitoring (table_name, start_time) VALUES ('triage_vital_sign', start_time);
END$$;


ALTER PROCEDURE public.proc_triage_vital_sign() OWNER TO lamisplus_etl;

--
-- Name: proc_update_hiv_status_tracker(); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.proc_update_hiv_status_tracker()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

update ods_hiv_status_tracker set hiv_status=biometric_status 
where biometric_status is not null and biometric_status != ''
and (biometric_status ilike '%invalid%' or biometric_status ilike '%duplicate%')
and (hiv_status not ilike '%art%' 
	 or hiv_status not ilike '%died%' 
	 or hiv_status not ilike '%death%'
	 or hiv_status not ilike '%stop%'
	 or hiv_status not ilike '%transfer%');

INSERT INTO cte_monitoring (table_name, start_time) VALUES ('ods_hiv_status_tracker', start_time);
END$$;


ALTER PROCEDURE public.proc_update_hiv_status_tracker() OWNER TO postgres;

--
-- Name: proc_update_public_period_table(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_update_public_period_table()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;

BEGIN
	SELECT TIMEOFDAY() INTO start_time;

update public.period 
set is_active = false 
where is_active;

update public.period 
set is_active = true 
where date = current_date-1;

INSERT INTO public.cte_monitoring (table_name, start_time) 
VALUES ('period', start_time);
END$$;


ALTER PROCEDURE public.proc_update_public_period_table() OWNER TO lamisplus_etl;

